// RUN: objc3c -fobjc-version=3 -fobjc3-strictness=strict --emit-module CORO04.objcmod --emit-interface CORO04.obji --emit-interface-mode=text --emit-interface-format=deterministic %s
// RUN: objc3c --emit-module CORO04-import.objcmod --import-interface CORO04.obji --emit-interface CORO04-roundtrip.obji --emit-interface-mode=text --emit-interface-format=deterministic
// RUN: objc3c --verify-interface CORO04.objcmod CORO04-roundtrip.obji %s
// RUN: objc3c --verify-interface CORO04-import.objcmod CORO04.obji %s
#pragma objc assume_nonnull begin
@interface CORO04Surface : NSObject
- (id _Nonnull)fetch:(id _Nonnull)seed async;
- (id _Nonnull)fetchChecked:(id _Nonnull)seed throws async;
- (id _Nonnull)fetchOnMain:(id _Nonnull)seed async __attribute__((objc_executor(main)));
@end
#pragma objc assume_nonnull end
